import socket
import struct
import math

class GameServer:
    def __init__(self, host='localhost', port=12345):
        self.host = host
        self.port = port
        self.server_socket = None
        self.clients = []

    def start(self):
        self.server_socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        self.server_socket.bind((self.host, self.port))
        self.server_socket.listen(5)

        print(f"Server started on {self.host}:{self.port}")

        while True:
            client_socket, address = self.server_socket.accept()
            self.clients.append(client_socket)

            print(f"New connection from {address}")

            data = client_socket.recv(1024)
            if not data:
                continue

            player_id, x, y = struct.unpack('iif', data)

            game_state = {
                'players': [
                    {'id': 1, 'x': 10.0, 'y': 20.0},
                    {'id': 2, 'x': 30.0, 'y': 40.0}
                ]
            }

            broadcast_game_state(client_socket, game_state)

    def broadcast_game_state(self, client_socket, game_state):
        for client in self.clients:
            if client != client_socket:
                data = struct.pack('iif', game_state['players'][0]['id'], game_state['players'][0]['x'], game_state['players'][0]['y'])
                client.send(data)

def main():
    server = GameServer()
